{
  "name": "GateMaster FASTag Automation",
  "description": "An automated gate management system simulation using FASTag RFID technology for residential and apartment complexes.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum GateStatus {
  CLOSED = 'CLOSED',
  OPENING = 'OPENING',
  OPEN = 'OPEN',
  CLOSING = 'CLOSING'
}

export enum TrafficLight {
  RED = 'RED',
  GREEN = 'GREEN'
}

export interface Vehicle {
  id: string;
  tagId: string;
  ownerName: string;
  apartmentNo: string;
  vehicleNo: string;
  lastEntry?: string;
}

export interface AccessLog {
  id: string;
  tagId: string;
  vehicleNo: string;
  timestamp: string;
  direction: 'IN' | 'OUT';
  status: 'AUTHORIZED' | 'DENIED';
}

export interface GateSystemConfig {
  mode: 'SINGLE_GATE' | 'DUAL_GATE';
  autoCloseDelay: number; // in seconds
}

import React, { useState, useEffect, useCallback } from 'react';
import { GateStatus, Vehicle, AccessLog, GateSystemConfig } from './types';
import Dashboard from './components/Dashboard';
import GateControl from './components/GateControl';
import VehicleManager from './components/VehicleManager';
import LogTable from './components/LogTable';
import HardwareDocs from './components/HardwareDocs';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'dashboard' | 'control' | 'vehicles' | 'logs' | 'docs'>('dashboard');
  const [gateStatus, setGateStatus] = useState<GateStatus>(GateStatus.CLOSED);
  const [vehicles, setVehicles] = useState<Vehicle[]>([
    { id: '1', tagId: 'FT12345678', ownerName: 'Rajesh Kumar', apartmentNo: 'A-101', vehicleNo: 'KA-01-MH-1234' },
    { id: '2', tagId: 'FT87654321', ownerName: 'Priya Sharma', apartmentNo: 'B-205', vehicleNo: 'KA-05-NB-5678' },
  ]);
  const [logs, setLogs] = useState<AccessLog[]>([]);
  const [config, setConfig] = useState<GateSystemConfig>({
    mode: 'SINGLE_GATE',
    autoCloseDelay: 5
  });

  const triggerGate = useCallback((direction: 'IN' | 'OUT', tagId: string) => {
    const vehicle = vehicles.find(v => v.tagId === tagId);
    const isValid = !!vehicle;

    const newLog: AccessLog = {
      id: Math.random().toString(36).substr(2, 9),
      tagId,
      vehicleNo: vehicle?.vehicleNo || 'UNKNOWN',
      timestamp: new Date().toLocaleString(),
      direction,
      status: isValid ? 'AUTHORIZED' : 'DENIED'
    };

    setLogs(prev => [newLog, ...prev]);

    if (isValid && gateStatus === GateStatus.CLOSED) {
      setGateStatus(GateStatus.OPENING);
      setTimeout(() => {
        setGateStatus(GateStatus.OPEN);
        setTimeout(() => {
          setGateStatus(GateStatus.CLOSING);
          setTimeout(() => {
            setGateStatus(GateStatus.CLOSED);
          }, 2000);
        }, config.autoCloseDelay * 1000);
      }, 2000);
    }
  }, [vehicles, gateStatus, config.autoCloseDelay]);

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-64 bg-indigo-900 text-white flex flex-col">
        <div className="p-6">
          <h1 className="text-2xl font-bold flex items-center gap-2">
            <i className="fas fa-gate"></i> GateMaster
          </h1>
          <p className="text-indigo-300 text-xs mt-1">FASTag Automation Pro</p>
        </div>

        <nav className="flex-1 mt-6">
          <SidebarItem 
            icon="fas fa-chart-line" 
            label="Dashboard" 
            active={activeTab === 'dashboard'} 
            onClick={() => setActiveTab('dashboard')} 
          />
          <SidebarItem 
            icon="fas fa-door-open" 
            label="Live Control" 
            active={activeTab === 'control'} 
            onClick={() => setActiveTab('control')} 
          />
          <SidebarItem 
            icon="fas fa-car" 
            label="Authorized Vehicles" 
            active={activeTab === 'vehicles'} 
            onClick={() => setActiveTab('vehicles')} 
          />
          <SidebarItem 
            icon="fas fa-history" 
            label="Access Logs" 
            active={activeTab === 'logs'} 
            onClick={() => setActiveTab('logs')} 
          />
          <SidebarItem 
            icon="fas fa-book" 
            label="Hardware & Documentation" 
            active={activeTab === 'docs'} 
            onClick={() => setActiveTab('docs')} 
          />
        </nav>

        <div className="p-4 border-t border-indigo-800">
          <div className="flex items-center gap-3">
            <div className={`w-3 h-3 rounded-full ${gateStatus === GateStatus.CLOSED ? 'bg-red-500' : 'bg-green-500'}`}></div>
            <span className="text-sm font-medium">Gate: {gateStatus}</span>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-8">
        <header className="mb-8 flex justify-between items-center">
          <div>
            <h2 className="text-3xl font-bold text-slate-800 capitalize">{activeTab}</h2>
            <p className="text-slate-500">System operation and configuration</p>
          </div>
          <div className="flex items-center gap-4">
             <div className="bg-white px-4 py-2 rounded-lg shadow-sm border flex items-center gap-3">
               <span className="text-sm text-slate-500">Mode:</span>
               <select 
                 value={config.mode}
                 onChange={(e) => setConfig({...config, mode: e.target.value as any})}
                 className="text-sm font-semibold outline-none bg-transparent"
               >
                 <option value="SINGLE_GATE">Single Gate (Bidir)</option>
                 <option value="DUAL_GATE">Dual Gate (Split)</option>
               </select>
             </div>
          </div>
        </header>

        {activeTab === 'dashboard' && <Dashboard logs={logs} vehicles={vehicles} />}
        {activeTab === 'control' && (
          <GateControl 
            gateStatus={gateStatus} 
            onScan={triggerGate} 
            mode={config.mode}
          />
        )}
        {activeTab === 'vehicles' && (
          <VehicleManager 
            vehicles={vehicles} 
            onAdd={(v) => setVehicles([...vehicles, { ...v, id: Date.now().toString() }])}
            onDelete={(id) => setVehicles(vehicles.filter(v => v.id !== id))}
          />
        )}
        {activeTab === 'logs' && <LogTable logs={logs} />}
        {activeTab === 'docs' && <HardwareDocs />}
      </main>
    </div>
  );
};

const SidebarItem: React.FC<{ icon: string, label: string, active: boolean, onClick: () => void }> = ({ icon, label, active, onClick }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-6 py-4 transition-colors ${active ? 'bg-indigo-800 border-l-4 border-indigo-400' : 'hover:bg-indigo-800/50'}`}
  >
    <i className={`${icon} w-5 text-indigo-300`}></i>
    <span className="text-sm font-medium">{label}</span>
  </button>
);

export default App;

import React from 'react';
import { Vehicle, AccessLog } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line } from 'recharts';

interface Props {
  logs: AccessLog[];
  vehicles: Vehicle[];
}

const Dashboard: React.FC<Props> = ({ logs, vehicles }) => {
  const authorizedLogs = logs.filter(l => l.status === 'AUTHORIZED');
  const entriesCount = authorizedLogs.filter(l => l.direction === 'IN').length;
  const exitsCount = authorizedLogs.filter(l => l.direction === 'OUT').length;

  // Fake chart data
  const data = [
    { name: '06:00', count: 12 },
    { name: '09:00', count: 45 },
    { name: '12:00', count: 30 },
    { name: '15:00', count: 25 },
    { name: '18:00', count: 58 },
    { name: '21:00', count: 20 },
  ];

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatCard title="Registered Vehicles" value={vehicles.length.toString()} icon="fa-car" color="bg-blue-500" />
        <StatCard title="Total Entries (Today)" value={entriesCount.toString()} icon="fa-sign-in-alt" color="bg-green-500" />
        <StatCard title="Total Exits (Today)" value={exitsCount.toString()} icon="fa-sign-out-alt" color="bg-orange-500" />
        <StatCard title="Security Alerts" value={logs.filter(l => l.status === 'DENIED').length.toString()} icon="fa-exclamation-triangle" color="bg-red-500" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-xl shadow-sm border">
          <h3 className="text-lg font-bold mb-6">Traffic Intensity</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={data}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="count" fill="#4f46e5" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border">
          <h3 className="text-lg font-bold mb-6">System Health</h3>
          <div className="space-y-4">
            <HealthItem label="RFID Reader (Entry)" status="ONLINE" />
            <HealthItem label="RFID Reader (Exit)" status="ONLINE" />
            <HealthItem label="Gate Servo Motor" status="ONLINE" />
            <HealthItem label="Loop Sensor" status="OFFLINE" warning="Loop sensor check required" />
            <HealthItem label="Connectivity" status="ONLINE" />
          </div>
        </div>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border">
        <h3 className="text-lg font-bold mb-4">Recent Activity</h3>
        <div className="divide-y">
          {logs.slice(0, 5).map(log => (
            <div key={log.id} className="py-3 flex justify-between items-center">
              <div className="flex items-center gap-4">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${log.status === 'AUTHORIZED' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                  <i className={`fas ${log.direction === 'IN' ? 'fa-arrow-right' : 'fa-arrow-left'}`}></i>
                </div>
                <div>
                  <p className="font-semibold text-sm">{log.vehicleNo}</p>
                  <p className="text-xs text-slate-500">{log.tagId} • {log.timestamp}</p>
                </div>
              </div>
              <span className={`px-3 py-1 rounded-full text-xs font-bold ${log.status === 'AUTHORIZED' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                {log.status}
              </span>
            </div>
          ))}
          {logs.length === 0 && <p className="text-center text-slate-500 py-10">No recent logs found</p>}
        </div>
      </div>
    </div>
  );
};

const StatCard = ({ title, value, icon, color }: { title: string, value: string, icon: string, color: string }) => (
  <div className="bg-white p-6 rounded-xl shadow-sm border flex items-center gap-5">
    <div className={`w-12 h-12 rounded-lg ${color} flex items-center justify-center text-white text-xl shadow-lg`}>
      <i className={`fas ${icon}`}></i>
    </div>
    <div>
      <p className="text-sm font-medium text-slate-500">{title}</p>
      <p className="text-2xl font-bold text-slate-800">{value}</p>
    </div>
  </div>
);

const HealthItem = ({ label, status, warning }: { label: string, status: 'ONLINE' | 'OFFLINE', warning?: string }) => (
  <div className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-100">
    <div>
      <p className="text-sm font-semibold text-slate-700">{label}</p>
      {warning && <p className="text-[10px] text-amber-600 italic">{warning}</p>}
    </div>
    <span className={`text-[10px] font-bold px-2 py-0.5 rounded border ${status === 'ONLINE' ? 'text-green-600 border-green-200 bg-green-50' : 'text-red-600 border-red-200 bg-red-50'}`}>
      {status}
    </span>
  </div>
);

export default Dashboard;

import React, { useState } from 'react';
import { GateStatus } from '../types';

interface Props {
  gateStatus: GateStatus;
  onScan: (direction: 'IN' | 'OUT', tagId: string) => void;
  mode: 'SINGLE_GATE' | 'DUAL_GATE';
}

const GateControl: React.FC<Props> = ({ gateStatus, onScan, mode }) => {
  const [inputTag, setInputTag] = useState('');

  const handleSimulateScan = (direction: 'IN' | 'OUT') => {
    if (!inputTag.trim()) {
      alert("Please enter a Tag ID for simulation");
      return;
    }
    onScan(direction, inputTag);
    setInputTag('');
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
      {/* Simulation Visualization */}
      <div className="bg-slate-900 rounded-2xl p-8 relative min-h-[400px] flex flex-col justify-between overflow-hidden">
        <div className="absolute top-4 left-4 flex gap-2">
           <div className={`w-4 h-4 rounded-full ${gateStatus === GateStatus.CLOSED ? 'bg-red-500 shadow-[0_0_10px_#ef4444]' : 'bg-slate-700'}`}></div>
           <div className={`w-4 h-4 rounded-full ${gateStatus === GateStatus.OPEN ? 'bg-green-500 shadow-[0_0_10px_#22c55e]' : 'bg-slate-700'}`}></div>
        </div>

        <div className="flex-1 flex flex-col items-center justify-center relative">
          {/* Gate Visual */}
          <div className="w-full h-2 bg-slate-700 absolute bottom-1/4"></div>

          {/* Arm Simulation */}
          <div 
            className={`w-full max-w-md h-4 bg-amber-500 rounded-full origin-left transition-all duration-[2000ms] ease-in-out absolute bottom-1/4 left-1/2 -translate-x-1/2
              ${gateStatus === GateStatus.OPEN ? '-rotate-90' : 'rotate-0'}`}
            style={{ 
              boxShadow: '0 4px 12px rgba(0,0,0,0.5)',
              border: '2px solid #b45309'
            }}
          >
            <div className="h-full w-full flex items-center justify-around px-10">
              <div className="w-8 h-1 bg-white/30 rounded-full"></div>
              <div className="w-8 h-1 bg-white/30 rounded-full"></div>
              <div className="w-8 h-1 bg-white/30 rounded-full"></div>
            </div>
          </div>

          <div className="text-white text-center z-10">
            <i className={`fas ${gateStatus === GateStatus.CLOSED ? 'fa-lock' : 'fa-lock-open'} text-6xl mb-4 text-indigo-400`}></i>
            <h3 className="text-2xl font-bold tracking-widest">{gateStatus}</h3>
            <p className="text-slate-400 text-sm mt-2">
              {mode === 'SINGLE_GATE' ? 'Bi-directional Single Lane' : 'Entry/Exit Split Mode'}
            </p>
          </div>
        </div>

        {/* Lane Indicators */}
        <div className="flex justify-between w-full mt-4 border-t border-slate-800 pt-6">
           <div className="text-center">
             <div className="text-slate-500 text-[10px] uppercase font-bold mb-1">Entry Sensor</div>
             <div className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center">
               <i className="fas fa-satellite-dish text-indigo-500"></i>
             </div>
           </div>
           <div className="text-center">
             <div className="text-slate-500 text-[10px] uppercase font-bold mb-1">Exit Sensor</div>
             <div className="w-10 h-10 rounded-full bg-slate-800 flex items-center justify-center">
               <i className="fas fa-satellite-dish text-indigo-500"></i>
             </div>
           </div>
        </div>
      </div>

      {/* Simulator Controls */}
      <div className="bg-white rounded-2xl p-8 border shadow-sm">
        <h3 className="text-xl font-bold text-slate-800 mb-6">Manual Simulation Tool</h3>

        <div className="space-y-6">
          <div className="p-4 bg-indigo-50 rounded-xl border border-indigo-100">
             <label className="block text-sm font-bold text-indigo-900 mb-2">Simulate FASTag Scan</label>
             <div className="flex gap-2">
               <input 
                 type="text" 
                 placeholder="Enter Tag ID (e.g. FT12345678)"
                 value={inputTag}
                 onChange={(e) => setInputTag(e.target.value.toUpperCase())}
                 className="flex-1 bg-white border border-indigo-200 px-4 py-3 rounded-lg text-sm font-mono focus:ring-2 focus:ring-indigo-400 outline-none"
               />
             </div>
             <div className="grid grid-cols-2 gap-3 mt-4">
               <button 
                 onClick={() => handleSimulateScan('IN')}
                 className="bg-indigo-600 hover:bg-indigo-700 text-white py-3 rounded-lg font-bold text-sm flex items-center justify-center gap-2"
               >
                 <i className="fas fa-sign-in-alt"></i> Entry Scan
               </button>
               <button 
                 onClick={() => handleSimulateScan('OUT')}
                 className="bg-indigo-600 hover:bg-indigo-700 text-white py-3 rounded-lg font-bold text-sm flex items-center justify-center gap-2"
               >
                 <i className="fas fa-sign-out-alt"></i> Exit Scan
               </button>
             </div>
          </div>

          <div>
             <h4 className="text-sm font-bold text-slate-700 mb-4">Quick Test Scenarios</h4>
             <div className="space-y-3">
               <TestScenarioButton 
                 label="Resident Entry (Rajesh)" 
                 onClick={() => { setInputTag('FT12345678'); handleSimulateScan('IN'); }} 
               />
               <TestScenarioButton 
                 label="Resident Exit (Priya)" 
                 onClick={() => { setInputTag('FT87654321'); handleSimulateScan('OUT'); }} 
               />
               <TestScenarioButton 
                 label="Unauthorized Vehicle" 
                 variant="danger"
                 onClick={() => { setInputTag('BAD-TAG-99'); onScan('IN', 'BAD-TAG-99'); }} 
               />
             </div>
          </div>

          <div className="pt-6 border-t">
            <p className="text-xs text-slate-500 leading-relaxed italic">
              * In a real scenario, the UHF RFID reader will push these Tag IDs automatically to the system via WebSockets or MQTT.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

const TestScenarioButton = ({ label, onClick, variant = 'primary' }: { label: string, onClick: () => void, variant?: 'primary' | 'danger' }) => (
  <button 
    onClick={onClick}
    className={`w-full text-left px-4 py-3 rounded-lg border flex items-center justify-between text-sm transition-all hover:translate-x-1 
    ${variant === 'primary' ? 'bg-slate-50 border-slate-200 hover:border-indigo-300 text-slate-700' : 'bg-red-50 border-red-100 text-red-700 hover:border-red-300'}`}
  >
    <span className="font-medium">{label}</span>
    <i className="fas fa-chevron-right opacity-30"></i>
  </button>
);

export default GateControl;

import React, { useState } from 'react';
import { Vehicle } from '../types';

interface Props {
  vehicles: Vehicle[];
  onAdd: (v: Omit<Vehicle, 'id'>) => void;
  onDelete: (id: string) => void;
}

const VehicleManager: React.FC<Props> = ({ vehicles, onAdd, onDelete }) => {
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    tagId: '',
    ownerName: '',
    apartmentNo: '',
    vehicleNo: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAdd(formData);
    setFormData({ tagId: '', ownerName: '', apartmentNo: '', vehicleNo: '' });
    setShowForm(false);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
      <div className="p-6 border-b flex justify-between items-center">
        <h3 className="text-lg font-bold text-slate-800">Vehicle Registry</h3>
        <button 
          onClick={() => setShowForm(!showForm)}
          className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-indigo-700"
        >
          {showForm ? 'Cancel' : 'Register Vehicle'}
        </button>
      </div>

      {showForm && (
        <form onSubmit={handleSubmit} className="p-6 bg-slate-50 border-b grid grid-cols-1 md:grid-cols-4 gap-4">
          <Input label="FASTag ID" value={formData.tagId} onChange={v => setFormData({...formData, tagId: v.toUpperCase()})} placeholder="FTxxxxxxxx" required />
          <Input label="Owner Name" value={formData.ownerName} onChange={v => setFormData({...formData, ownerName: v})} placeholder="e.g. Rahul Singh" required />
          <Input label="Apartment No" value={formData.apartmentNo} onChange={v => setFormData({...formData, apartmentNo: v})} placeholder="e.g. C-404" required />
          <Input label="Vehicle No" value={formData.vehicleNo} onChange={v => setFormData({...formData, vehicleNo: v.toUpperCase()})} placeholder="KA-01-..." required />
          <div className="md:col-span-4 flex justify-end">
             <button type="submit" className="bg-indigo-600 text-white px-8 py-2 rounded-lg font-bold shadow-md hover:bg-indigo-700">Save Vehicle</button>
          </div>
        </form>
      )}

      <table className="w-full text-left">
        <thead className="bg-slate-50 border-b uppercase text-[10px] font-bold text-slate-500">
          <tr>
            <th className="px-6 py-4">Vehicle Details</th>
            <th className="px-6 py-4">Owner / Unit</th>
            <th className="px-6 py-4">FASTag ID</th>
            <th className="px-6 py-4 text-right">Action</th>
          </tr>
        </thead>
        <tbody className="divide-y">
          {vehicles.map(vehicle => (
            <tr key={vehicle.id} className="hover:bg-slate-50/50 transition-colors">
              <td className="px-6 py-4">
                <p className="font-bold text-slate-800">{vehicle.vehicleNo}</p>
                <p className="text-xs text-slate-400">ID: {vehicle.id}</p>
              </td>
              <td className="px-6 py-4">
                <p className="text-sm font-medium text-slate-700">{vehicle.ownerName}</p>
                <p className="text-xs text-slate-500">Unit: {vehicle.apartmentNo}</p>
              </td>
              <td className="px-6 py-4">
                <code className="text-xs font-mono bg-slate-100 px-2 py-1 rounded text-indigo-700 font-bold">{vehicle.tagId}</code>
              </td>
              <td className="px-6 py-4 text-right">
                <button onClick={() => onDelete(vehicle.id)} className="text-red-400 hover:text-red-600 transition-colors">
                  <i className="fas fa-trash-alt"></i>
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

const Input = ({ label, value, onChange, placeholder, required }: any) => (
  <div>
    <label className="block text-xs font-bold text-slate-500 uppercase mb-1">{label}</label>
    <input 
      type="text" 
      value={value}
      onChange={e => onChange(e.target.value)}
      className="w-full border rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-400 outline-none" 
      placeholder={placeholder}
      required={required}
    />
  </div>
);

export default VehicleManager;

import React from 'react';
import { AccessLog } from '../types';

interface Props {
  logs: AccessLog[];
}

const LogTable: React.FC<Props> = ({ logs }) => {
  return (
    <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
      <div className="p-6 border-b flex justify-between items-center bg-slate-50/50">
        <h3 className="text-lg font-bold text-slate-800">Full Access History</h3>
        <button className="text-indigo-600 text-sm font-bold flex items-center gap-2 hover:underline">
          <i className="fas fa-download"></i> Export CSV
        </button>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="bg-slate-50/80 uppercase text-[10px] font-black tracking-wider text-slate-400 border-b">
            <tr>
              <th className="px-6 py-4">Time</th>
